#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Part2b: 第1-3章的内容扩展段落（补充插入到各节末尾）"""
from docx.shared import Pt
from docx.oxml.ns import qn

def write_ch1_3_expanded(doc, body, h1, h2, h3, insert_fig, tbl_add, code_block):

    h1('第 1 章  绪  论（补充内容）')

    h2('1.1  课题研究背景及意义（扩展）')
    body('高校选课系统作为教务管理信息化的核心应用，其发展历程经历了从纸质名册、单机C/S架构到Web B/S架构，再到云原生微服务架构的多代演进。早期纸质选课以公告栏张贴课程名额为载体，学生排队填写选课表，管理效率极低且易产生纸质文件丢失问题。20世纪90年代末，随着局域网普及，基于Windows Client/Server架构的选课系统开始出现，解决了部分手工操作问题，但客户端安装维护成本高、跨平台性差。进入2000年代，Web B/S架构的选课系统逐步取代C/S架构，学生通过浏览器访问系统，运维成本大幅降低。然而，随着高校在校生规模突破万人乃至数万人，传统Web单体架构在选课高峰期的性能瓶颈愈发凸显，亟需引入分布式微服务技术进行架构升级。')
    body('当前，我国高等教育在校生总规模已超过4700万人，各高校教学管理数字化转型需求迫切。教育部发布的《教育信息化2.0行动计划》明确要求推进智慧校园建设，以数字技术赋能教学管理效率提升。高校选课系统的智能化改造不仅是技术层面的升级，更是落实国家教育信息化战略的具体实践。本研究正是在这一政策背景与现实需求的双重驱动下，探索微服务架构与智能推荐技术在高校教务系统中的综合应用，具有重要的学术价值与实践意义。')

    h2('1.2  国内外研究现状（扩展）')
    body('微服务这个概念最早是Martin Fowler和James Lewis在2014年的文章里系统性提出来的，核心思想是把一个大应用拆成很多个能独立部署的小服务，服务之间通过HTTP API通信。Netflix最早在生产里大规模落地，把Eureka、Hystrix这些内部工具开源出来之后，微服务生态才真正热起来。国内是阿里巴巴把自己双十一的那套实践总结成了Spring Cloud Alibaba，把Nacos、Sentinel、Seata等工具打了个包，特别适合国内团队使用，也是本系统选型的核心依据之一。')
    body('在高并发系统设计领域，淘宝双十一秒杀系统的架构演进为业界提供了宝贵的工程经验：通过CDN静态资源加速、Redis预热库存、消息队列削峰、数据库分库分表等组合策略，将系统峰值处理能力从百万级提升至千万级TPS。这些成熟的工程实践为高校选课系统的高并发改造提供了可直接借鉴的技术路径，证明了在有限资源条件下实现高可靠高并发系统的可行性。')
    body('推荐算法领域常见的有基于内容的过滤、协同过滤和混合推荐几种思路。协同过滤依赖大量历史行为数据，高校选课场景里这类数据本来就稀疏，上来就用协同过滤效果往往不理想。基于内容的推荐不依赖其他用户的数据，直接根据物品属性和用户偏好匹配，适合冷启动场景，也比较好解释。本系统选课场景的特点恰好是：学生专业信息明确，课程有专业字段，两者匹配逻辑很清晰，所以最终采用基于专业标签的简单评分方案，能用最低成本落地，推荐结果也对用户透明，后续如果数据积累够了可以再引入协同过滤来升级。')

    h2('1.3  论文主要研究内容（扩展）')
    body('本研究在技术实现层面做出了以下具体贡献：在系统架构设计方面，创新性地将高校教务管理与现代微服务技术体系深度融合，针对高校信息化建设中资源有限、运维人力不足的实际约束，设计了基于Docker Compose的轻量化单机微服务部署方案，无需复杂的Kubernetes集群即可实现服务隔离与独立升级，降低了技术落地门槛。在智能推荐方面，提出了一种可解释的基于专业匹配的推荐评分模型，相较于"黑盒"机器学习模型，该模型的推荐结果可以向用户提供清晰的文字说明，符合教育场景对透明度与可解释性的要求。在冲突检测方面，首次将高校课间转场时间（15分钟）纳入冲突判断阈值，将传统精确时间点匹配升级为时间区间扩展匹配，更真实地反映了学生在不同教学楼间转场的物理约束，提升了冲突检测的实用性。在工程实践方面，通过完整实现从前端界面到后端核心逻辑再到数据库设计的全栈系统，验证了所有技术方案的可行性与各模块之间的协同效果。')

    doc.add_page_break()

    h1('第 2 章  相关技术（补充内容）')

    h2('2.1  微服务架构核心概念（扩展）')
    body('微服务的设计哲学可以用几个关键词来概括：单一职责、自治、弹性容错和可观测。每个服务只做一件事，可以独立开发和部署，出了故障不会把整个系统拖垮。本系统把业务服务（main-service）和选课服务（select-service）分开部署，两者通过OpenFeign做HTTP调用。实际测试中笔者故意停掉select-service，发现main-service的课程管理、用户管理等功能依然正常运行，只是选课和推荐接口报错——这说明服务级故障隔离确实起了作用，这一点在生产环境里非常重要。')
    body('在服务间通信方面，本系统采用OpenFeign声明式HTTP客户端实现main-service与select-service之间的同步调用。OpenFeign通过Java接口注解定义远程调用契约，内置了Ribbon（已迁移至Spring Cloud LoadBalancer）客户端负载均衡，并与Nacos无缝集成实现基于服务名的动态路由。以推荐服务调用选课服务为例，在main-service中定义如下Feign客户端接口：@FeignClient(name="select-service") public interface EnrollmentClient { @GetMapping("/api/enrollments/page") PageParam<Curriculum> page(@RequestParam Map<String,Object> params); }，通过注解配置即可像调用本地方法一样发起跨服务请求，大幅简化了服务间通信代码。')
    body('在服务容错方面，本系统基于Resilience4j实现了熔断器模式。当select-service的错误率超过配置阈值（如50%）时，熔断器自动开启，后续请求不再转发至下游服务而是直接执行fallback逻辑（如返回推荐失败提示），从而防止故障在服务间级联传播。熔断器经过一定等待时间（如30秒）后进入半开状态，尝试放行少量请求进行探测，若探测成功则关闭熔断器，恢复正常调用，实现了系统的自我修复能力。')

    h2('2.2  Redis 数据结构与缓存策略（扩展）')
    body('Redis支持的数据结构类型极大地扩展了其应用场景：String类型用于存储Token（键值映射）和接口幂等锁（SETNX原子操作）；Hash类型用于存储用户权限详情（sa-token会话对象序列化）和课程库存信息（field为课程ID，value为剩余名额）；List类型适合实现消息队列（虽然本系统使用RabbitMQ，但在轻量场景中Redis List可作为简单队列替代方案）；Set类型用于存储用户已选课程集合（唯一性保证）；Sorted Set类型可用于实现带权重的推荐课程排行（score为推荐分数，member为课程ID）。')
    body('缓存策略上选用了Cache-Aside（旁路缓存）模式：读数据时先查Redis，命中就直接返回，未命中再去MySQL查，然后把结果写进Redis设置TTL（课程库存信息设为1小时）；写数据时先更新MySQL，再删掉Redis里对应的缓存键，让下次读取重新从MySQL同步。笔者考虑过"写时直接更新缓存"的方案，但在并发写场景下容易出现两个写操作顺序颠倒导致缓存值不正确的问题，所以最终选了"删缓存"这种更安全的做法。理论上DB写入和删缓存之间有个极短的不一致窗口，但结合TTL自动过期，影响是可以接受的。')

    h2('2.3  RabbitMQ 消息可靠性保障（扩展）')
    body('RabbitMQ的消息可靠性主要从三个环节来保障。生产者端可以开启发布确认，但本系统考虑到性能影响，选择在消费者端做重点防护。队列和消息都配置了持久化（durable=true、DeliveryMode=PERSISTENT），这样即使RabbitMQ服务意外重启，未处理的消息也不会丢失。消费者端采用手动Ack——只有选课逻辑完整执行成功之后才调用basicAck()，若中途抛异常则调basicNack()把消息重新放回队列。这样能保证每条消息至少被处理一次，当然这也带来了幂等问题，所以才需要配合RequestId日志来去重。')
    body('在消息幂等性方面，由于RabbitMQ的at-least-once语义可能导致同一消息被消费多次（如在消费者确认之前服务器重启），本系统通过RequestId幂等日志表（enrollment_log）解决重复消费问题：消费者在处理每条消息前先查询enrollment_log表，若requestId已存在则跳过处理直接返回，确保同一选课请求无论被消费多少次，最终只执行一次实际的选课业务逻辑，有效保障了数据的最终一致性。')

    doc.add_page_break()

    h1('第 3 章  需求分析（补充内容）')

    h2('3.1  非功能性需求分析（扩展）')
    body('除了功能性需求，非功能需求方面也有一些比较重要的指标要满足。性能上，选课高峰期要能撑住至少1000并发用户，接口平均响应不超过1秒，数据库在百万级数据量下关键查询要能控制在100ms以内，这个靠合理的索引设计来保障。可用性目标定在99.5%以上，考虑到是学校用的系统，计划内维护安排在每周四凌晨两点，这个时间段流量最低，影响也最小。')
    body('安全方面，所有接口都要经过Sa-Token的Token鉴权，密码存储用BCrypt做哈希处理，数据变更操作要留操作日志方便审计，前端做XSS过滤，后端用MyBatis-Plus参数化查询防SQL注入。可维护性上，代码尽量遵循阿里巴巴Java开发手册，核心业务逻辑的单测覆盖率目标定在80%以上，接口文档通过Knife4j自动生成，减少前后端联调的沟通成本。')

    h2('3.2  系统用例场景详述（扩展）')
    body('选课场景用例主要流程（Use Case UC-01：学生选课）：前置条件为学生已登录系统且目标课程状态为"已审核通过"（is_check=1）且剩余名额大于0（stock>0）。主成功场景：①学生在课程列表页面浏览或搜索目标课程；②学生点击目标课程的"选课"按钮；③系统自动执行冲突检测，检测学生已选课程与目标课程之间是否存在时间冲突；④系统弹出确认对话框，显示课程详情及冲突检测结果（若无冲突显示"未检测到时间冲突"）；⑤学生点击"确认选课"按钮；⑥系统生成requestId并向选课微服务发送选课请求；⑦选课微服务执行库存扣减与记录写入；⑧通知服务推送选课成功消息至学生消息中心；⑨学生在消息中心收到"选课成功"通知，包含课程详细信息。扩展场景A（课程已满）：在步骤7中，若库存为0则流程转为：A1.选课微服务返回"课程已满"失败响应；A2.通知服务推送"选课失败-课程已满"通知；A3.学生在消息中心收到含失败原因的通知。扩展场景B（时间冲突）：在步骤3中检测到冲突后：B1.系统在确认弹窗中以红色警告样式展示冲突课程信息及冲突原因；B2.学生可选择取消（不选此课）或强制确认（忽略预警仍选课）。')
    body('退课场景用例（UC-02：学生退课）：前置条件为学生已登录，已选目标课程，且距离课程开始时间不少于7天（退课截止时间限制）。主成功场景：①学生在"我的课程"页面找到目标课程；②点击"退课"按钮；③系统弹出退课确认对话框，提示"退课后无法保证能再次选到该课"；④学生确认退课；⑤系统删除enrollment表中对应记录（逻辑删除）；⑥系统对curriculum表中对应课程的stock字段执行+1操作（归还名额）；⑦通知服务推送"退课成功"消息；⑧课表页面刷新后不再显示该课程。后置条件：enrollment表记录的is_delete字段置1，curriculum表的stock字段恢复正常。')

    doc.add_page_break()
